36	const PROCESSING_FEE = 5;
37	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
38	const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15;
39	const BLOCK_OF_THREE_DISCOUNT = 15;
40	const CURSE_SURCHARGE_RATE = 0.5;
41	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
42	const HIGH_ENCHANTMENT_THRESHOLD = 5;
43	const LOYALTY_DISCOUNT_RATE = 0.2;
44	const LOYALTY_YEARS_THRESHOLD = 2;
45	
46	type CatalogEntry = { basePremium: number; insuranceValue: number };
47	
48	const ITEM_CATALOG: Record<string, CatalogEntry> = {
49	  sword: { basePremium: 100, insuranceValue: 1000 },
50	  amulet: { basePremium: 60, insuranceValue: 600 },
51	  staff: { basePremium: 80, insuranceValue: 800 },
52	  potion: { basePremium: 40, insuranceValue: 400 },
53	  rune: { basePremium: 25, insuranceValue: 250 },
54	  moonstone: { basePremium: 25, insuranceValue: 250 },
55	};
56	
57	const catalogEntryFor = (type: string): CatalogEntry => {
58	  const entry = ITEM_CATALOG[type];
59	  if (!entry) {
60	    throw new Error(`Unknown item type: ${type}`);
61	  }
62	  return entry;
63	};
64	
65	const DEDUCTIBLE = 100;
66	const CAP_MULTIPLIER = 2;
67	
68	const BLOCK_OF_THREE_ELIGIBLE_TYPES = ["rune", "moonstone"];
69	
70	const blockOfThreeDiscount = (alikeComponentCount: number): number =>
71	  alikeComponentCount === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
72	
73	const countItemsOfType = (items: Item[], type: string): number =>
74	  items.filter((item) => item.type === type).length;
75	
76	const isCursed = (item: Item): boolean => item.cursed === true;
77	const isHighlyEnchanted = (item: Item): boolean =>
78	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
79	
80	const ITEM_SURCHARGE_RATES: ReadonlyArray<{
81	  applies: (item: Item) => boolean;
82	  rate: number;
83	}> = [
84	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
85	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_SURCHARGE_RATE },
86	];
87	
88	const basePremiumFor = (item: Item): number => catalogEntryFor(item.type).basePremium;
89	
90	const surchargesForItem = (item: Item): number => {
91	  const base = basePremiumFor(item);
92	  return ITEM_SURCHARGE_RATES.reduce(
93	    (sum, { applies, rate }) => sum + (applies(item) ? base * rate : 0),
94	    0,
95	  );
96	};
97	
98	const sumItemSpecificSurcharges = (items: Item[]): number =>
99	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
100	
101	const calculateBasePremium = (items: Item[]): number => {
102	  const subtotal = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
103	  const totalDiscount = BLOCK_OF_THREE_ELIGIBLE_TYPES.reduce(
104	    (sum, type) => sum + blockOfThreeDiscount(countItemsOfType(items, type)),
105	    0,
106	  );
107	  return subtotal - totalDiscount;
108	};
109	
110	const firstContractSurcharge = (basePremium: number): number =>
111	  basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
112	
113	const qualifiesForLoyaltyDiscount = (yearsWithMHPCO: number): boolean =>
114	  yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
115	
116	const loyaltyDiscount = (basePremium: number, yearsWithMHPCO: number): number =>
117	  qualifiesForLoyaltyDiscount(yearsWithMHPCO) ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
118	
119	const followUpContractDiscount = (basePremium: number, isFollowUp: boolean): number =>
120	  isFollowUp ? basePremium * FOLLOW_UP_CONTRACT_DISCOUNT_RATE : 0;
121	
122	const quote = (
123	  step: QuoteStep,
124	  customer: Scenario["customer"],
125	  isFollowUp: boolean,
126	): QuoteResult => {
127	  const basePremium = calculateBasePremium(step.items);
128	  const itemSurcharges = sumItemSpecificSurcharges(step.items);
129	  const premium = Math.ceil(
130	    basePremium +
131	      itemSurcharges +
132	      firstContractSurcharge(basePremium) -
133	      loyaltyDiscount(basePremium, customer.yearsWithMHPCO) -
134	      followUpContractDiscount(basePremium, isFollowUp) +
135	      PROCESSING_FEE,
136	  );
137	  return { premium };
138	};
139	
140	type Policy = { items: Item[]; cap: number };
141	
142	const insuranceSumOf = (items: Item[]): number =>
143	  items.reduce((sum, item) => sum + catalogEntryFor(item.type).insuranceValue, 0);
144	
145	const claim = (step: ClaimStep, policy: Policy): ClaimResult => {
146	  const grossPayout = step.incident.damages.reduce(
147	    (sum, dmg) => sum + Math.max(0, dmg.amount - DEDUCTIBLE),
148	    0,
149	  );
150	  const cappedPayout = Math.min(grossPayout, policy.cap);
151	  return { payout: Math.floor(cappedPayout), remainingCap: policy.cap - cappedPayout };
152	};
153	
154	export const runScenario = (scenario: Scenario): ScenarioResult => {
155	  const policies: Policy[] = [];
156	  let priorQuoteCount = 0;
157	  const results: StepResult[] = scenario.steps.map((step) => {
158	    if (step.op === "quote") {
159	      const isFollowUp = priorQuoteCount > 0;
160	      priorQuoteCount += 1;
161	      const result = quote(step, scenario.customer, isFollowUp);
162	      policies.push({ items: step.items, cap: insuranceSumOf(step.items) * CAP_MULTIPLIER });
163	      return result;
164	    }
165	    const policy = policies[step.policy];
166	    const result = claim(step, policy);
167	    policy.cap = result.remainingCap;
168	    return result;
169	  });
170	  return { results };
171	};
